import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate, useLocation } from "react-router-dom";
import { ArrowLeft, Sparkles, ChefHat, HelpCircle } from "lucide-react";
import { useLoginRequired } from "@/hooks/useLoginRequired";
import { Separator } from "@/components/ui/separator";
import AIVideoGenerator from "@/components/ai-recipe/AIVideoGenerator";


const AIRecipeSelect = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { requireLogin } = useLoginRequired();

  const fromPath = (location.state as any)?.from || "/";

  return (
    <div className="min-h-screen flex flex-col bg-background">
      {/* Header */}
      <div className="px-4 py-3 border-b bg-background shrink-0 sticky top-14 z-10">
        <div className="flex items-center justify-between">
          <button
            onClick={() => navigate(fromPath, { replace: true })}
            className="p-1 -ml-1 hover:bg-muted rounded-md"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <div className="flex items-center gap-2">
            <Sparkles className="h-4 w-4 text-primary" />
            <h2 className="font-medium">{t("aiRecipe.title")}</h2>
          </div>
          <div className="w-6" />
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 flex flex-col items-center px-4 pt-10 pb-4 sm:pt-16 sm:px-6 sm:pb-6 gap-4 sm:gap-6 max-w-md mx-auto w-full">

        {/* Search & Random recipe section - on top */}
        <div className="w-full space-y-1">
          <h3 className="text-sm font-medium text-center text-muted-foreground">{t("aiRecipe.videoGen.title")}</h3>
          <AIVideoGenerator />
        </div>

        {/* Divider */}
        <div className="w-full flex items-center gap-3">
          <Separator className="flex-1" />
          <span className="text-xs text-muted-foreground shrink-0">{t("aiRecipe.selectTitle")}</span>
          <Separator className="flex-1" />
        </div>

        <div className="grid gap-3 w-full">
          {/* 吃什么 */}
          {/* 吃什么 - hidden */}

          {/* 做什么 */}
          <button
            onClick={() => { if (requireLogin()) navigate("/ai-recipe/how-to-cook", { state: { from: fromPath } }); }}
            className="flex items-start gap-3 p-4 sm:p-5 rounded-2xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all duration-200 group text-left"
          >
            <div className="w-11 h-11 sm:w-14 sm:h-14 rounded-xl bg-accent flex items-center justify-center shrink-0 group-hover:scale-105 transition-transform">
              <ChefHat className="h-5 w-5 sm:h-7 sm:w-7 text-accent-foreground" />
            </div>
            <div className="space-y-1">
              <h3 className="font-semibold text-base">
                {t("aiRecipe.howToCook")}
              </h3>
              <p className="text-xs text-muted-foreground leading-relaxed">
                {t("aiRecipe.howToCookDesc")}
              </p>
            </div>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIRecipeSelect;
